require "config.SeasonConfig"

local GUIDeadSummary = class("", IGUILayout)

function GUIDeadSummary:onLoad()

    self.rank = 0
    self.kilNum = 0
    self.goldNum = 0
    self.score = 0
    self.honorId = 0

    self.btnBack = self:getChildWindow("LuckySkyDeadSummary-Back-Button", GUIType.Button)
    self.btnWatch = self:getChildWindow("LuckySkyDeadSummary-Watch-Button", GUIType.Button)
    self.btnAgain = self:getChildWindow("LuckySkyDeadSummary-Again-Button", GUIType.Button)

    self.btnBack:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.clickUI()
        GamePacketSender:sendPlayerBackHallEvent()
    end)
    self.btnWatch:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.clickUI()
        RootGuiLayout.Instance():showMainControl()
    end)
    self.btnAgain:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.clickUI()
        GamePacketSender:sendPlayerNextGameEvent()
    end)

    self.tvRank = self:getChildWindow("LuckySkyDeadSummary-Rank-Num", GUIType.StaticText)
    self.tvKillNum = self:getChildWindow("LuckySkyDeadSummary-Kill-Num", GUIType.StaticText)
    self.tvGoldNum = self:getChildWindow("LuckySkyDeadSummary-Gold-Num", GUIType.StaticText)
    self.tvScore = self:getChildWindow("LuckySkyDeadSummary-Score-Num", GUIType.StaticText)

    self.ivDanIcon = self:getChildWindow("LuckySkyDeadSummary-Dan-Icon", GUIType.StaticImage)
    self.ivFlagIcon = self:getChildWindow("LuckySkyDeadSummary-Flag-Icon", GUIType.StaticImage)
    self.tvDanName = self:getChildWindow("LuckySkyDeadSummary-Dan-Name-Text", GUIType.StaticText)

    --多语言
    self:getChildWindow("LuckySkyDeadSummary-Title", GUIType.StaticText):SetText(Lang:getString("lucky.sky.dead.summary.title"))
    self:getChildWindow("LuckySkyDeadSummary-Rank-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.dead.summary.rank"))
    self:getChildWindow("LuckySkyDeadSummary-kill-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.dead.summary.kill"))
    self:getChildWindow("LuckySkyDeadSummary-Back-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.dead.summary.back"))
    self:getChildWindow("LuckySkyDeadSummary-Watch-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.dead.summary.watch"))
    self:getChildWindow("LuckySkyDeadSummary-Again-Text", GUIType.StaticText):SetText(Lang:getString("lucky.sky.dead.summary.again"))

    self:registerDataCallBack("DeadSummaryData", function(data)
        self:onUpdateDeadSummaryData(data)
    end, JsonBuilderProcessor)

end

function GUIDeadSummary:onUpdateDeadSummaryData(data)
    self.rank = data.rank
    self.kilNum = data.kills
    self.goldNum = data.gold
    self.score = data.result_add_integral
    self.honorId = data.honorId
    self:show()
end

function GUIDeadSummary:onShow()
    GUIMain:hideAllLayout()
    self.tvRank:SetText(string.format("No.%s",tostring(self.rank)))
    self.tvKillNum:SetText(self.kilNum)
    self.tvGoldNum:SetText(string.format("+ %s", tostring(self.goldNum)))
    local scoreText = "+" .. self.score
    if tonumber(self.score) < 0 then
        scoreText = self.score
    end
    self.tvScore:SetText(scoreText)

    local curSeason = SeasonConfig:getSeasonByHonorId(self.honorId)
    if not curSeason then
        return
    end
    self.ivDanIcon:SetImage(curSeason.icon)
    self.ivFlagIcon:SetImage(curSeason.flag)
    self.tvDanName:SetText(Lang:getString(curSeason.honorName))
end

return GUIDeadSummary